/*
 * EMAIL PREPROCESSOR
 * ──────────────────────────────────────────────────────────────────
 * 1. Detects and rejects auto-responder loops (RFC 3834 compliant)
 * 2. Sanitises HTML body → clean plain text
 * 3. Stamps traceId for correlation across all downstream nodes
 * 4. Truncates body to 2500 chars to stay within token budget
 */

const raw = $input.first().json;

// ── Auto-responder loop guard (RFC 3834) ──────────────────────────
const LOOP_SIGNALS = [
  raw.headers?.['auto-submitted']                && raw.headers['auto-submitted'] !== 'no',
  raw.headers?.['x-auto-response-suppress'],
  raw.headers?.['precedence'] === 'bulk',
  raw.headers?.['precedence'] === 'auto-reply',
  /^(automatic reply|out of office|auto:|noreply@|no-reply@)/i.test(raw.subject ?? ''),
  /^re:re:re:/i.test(raw.subject ?? ''),
];

if (LOOP_SIGNALS.some(Boolean)) {
  throw new Error(`LOOP_GUARD: auto-responder email discarded [subject: ${(raw.subject ?? '').slice(0,60)}]`);
}

// ── Body sanitisation ─────────────────────────────────────────────
const stripHtml = (s) => (s ?? '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<br\s*\/?>/gi, '\n')
  .replace(/<p[^>]*>/gi,   '\n')
  .replace(/<[^>]+>/g,      '')
  .replace(/&nbsp;/g,       ' ')
  .replace(/&amp;/g,        '&')
  .replace(/&lt;/g,         '<')
  .replace(/&gt;/g,         '>')
  .replace(/[ \t]+/g,       ' ')
  .replace(/\n{3,}/g,       '\n\n')
  .trim();

const rawBody   = raw.text || stripHtml(raw.html) || raw.snippet || '';
const bodyClean = rawBody.length > 2500 ? rawBody.slice(0, 2500) + '…[truncated]' : rawBody;

// ── Sender extraction ─────────────────────────────────────────────
const fromObj    = raw.from?.value?.[0] ?? {};
const senderName = fromObj.name || fromObj.address?.split('@')[0] || 'there';
const senderEmail = (fromObj.address || raw.from?.text || '').toLowerCase().trim();

const traceId = `tr-email-${Date.now().toString(36)}`;

return [{
  json: {
    traceId,
    emailId:      raw.id,
    threadId:     raw.threadId,
    subject:      raw.subject || '(no subject)',
    senderName,
    senderEmail,
    body:         bodyClean,
    snippet:      (raw.snippet || '').slice(0, 200),
    receivedAt:   raw.date || new Date().toISOString(),
    labels:       raw.labelIds || []
  }
}];

/*
 * CLASSIFICATION PARSER + BUSINESS RULE LAYER
 * ──────────────────────────────────────────────────────────────────
 * Parses the LLM JSON response defensively.
 * Applies deterministic business rules that override AI judgment
 * — this is the safety net between AI and real customer comms.
 */

const email  = $input.all()[0].json;
const aiText = $input.all()[1]?.json?.message?.content ?? '{}';

// ── Safe JSON parse ───────────────────────────────────────────────
let cls;
try {
  cls = JSON.parse(aiText.replace(/```json|```/g, '').trim());
} catch (_) {
  cls = {
    intent: 'general', priority: 'medium',
    sentiment: 'neutral', frustrationScore: 0,
    keyTopics: [], requiresHumanReview: true,
    reviewReason: 'JSON_PARSE_FAILURE',
    confidence: 0.0, oneSentenceSummary: 'Classification unavailable'
  };
}

// ── Deterministic override rules (always beat AI) ────────────────
const LEGAL_PATTERN  = /lawsuit|attorney|legal action|refund demand|chargeback|fraud/i;
const URGENT_PATTERN = /urgent|critical|outage|data loss|emergency|hack/i;

if (LEGAL_PATTERN.test(email.body)) {
  cls.requiresHumanReview = true;
  cls.priority            = 'high';
  cls.reviewReason        = 'LEGAL_LANGUAGE_DETECTED';
}
if (URGENT_PATTERN.test(email.subject + ' ' + email.body)) {
  cls.requiresHumanReview = true;
  cls.priority            = 'high';
  cls.reviewReason        = cls.reviewReason || 'URGENCY_PATTERN_DETECTED';
}
if (cls.confidence < 0.72) {
  cls.requiresHumanReview = true;
  cls.reviewReason        = cls.reviewReason || `LOW_CONFIDENCE:${cls.confidence}`;
}

return [{ json: { ...email, classification: cls } }];

// Build rich Slack review-queue notification
const d = $input.first().json;
const c = d.classification;

const PRIORITY_EMOJI = { high: '🔴', medium: '🟡', low: '🟢' };

return [{
  json: {
    ...d,
    slackBlocks: [
      {
        type: 'header',
        text: { type: 'plain_text', text: `${PRIORITY_EMOJI[c.priority] ?? '📧'} Email Review Required`, emoji: true }
      },
      {
        type: 'section',
        fields: [
          { type: 'mrkdwn', text: `*From:*\n${d.senderName} <${d.senderEmail}>` },
          { type: 'mrkdwn', text: `*Intent:*\n${c.intent}` },
          { type: 'mrkdwn', text: `*Priority:*\n${c.priority}` },
          { type: 'mrkdwn', text: `*Confidence:*\n${(c.confidence * 100).toFixed(0)}%` },
          { type: 'mrkdwn', text: `*Sentiment:*\n${c.sentiment} (${c.frustrationScore}/10)` },
          { type: 'mrkdwn', text: `*Review Reason:*\n${c.reviewReason ?? 'N/A'}` }
        ]
      },
      { type: 'section', text: { type: 'mrkdwn', text: `*Subject:*\n${d.subject}` } },
      { type: 'section', text: { type: 'mrkdwn', text: `*Summary:*\n${c.oneSentenceSummary}` } },
      {
        type: 'context',
        elements: [{ type: 'mrkdwn', text: `Email ID: \`${d.emailId}\` | Trace: \`${d.traceId}\`` }]
      },
      { type: 'divider' }
    ]
  }
}];

// Merge email context + AI reply; add abuse-prevention guardrails
const email   = $input.all()[0].json;
const replyRaw = $input.all()[1]?.json?.message?.content;

if (!replyRaw || replyRaw.trim().length < 20) {
  throw new Error(`AI_REPLY_EMPTY: empty or invalid reply generated for emailId=${email.emailId}`);
}

// Safety: strip any accidental AI self-disclosure
const FORBIDDEN = /\b(as an ai|i am an ai|i'm an ai|artificial intelligence|language model|chatgpt|openai)\b/gi;
const replyClean = replyRaw.replace(FORBIDDEN, '').trim();

return [{
  json: {
    ...email,
    replyBody:    replyClean,
    replySubject: email.subject.startsWith('Re:') ? email.subject : `Re: ${email.subject}`
  }
}];
